rules.pseudocode:
if last_action == 'eat' and last_action_result.consumed:
    energy = clip(energy + energy_gain_eat * food_palatability, 0, 1)
elif last_action in ['move_up','move_down','move_left','move_right']:
    energy = clip(energy - c_move, 0, 1)
else:  # stay or failed eat
    energy = clip(energy - c_stay, 0, 1)

for each action a in available_actions:
    if a == 'eat' and food_at_current_position:
        s_pred[a] = clip(s_t + energy_gain_eat, 0, 1)
    elif a in ['move_up','move_down','move_left','move_right']:
        if a == direction_toward_nearest_food:
            s_pred[a] = s_t - c_move_toward
        else:
            s_pred[a] = s_t - c_move
    elif a == 'stay':
        s_pred[a] = s_t - c_stay
    if a == 'eat' and not food_at_current_position:
        s_pred[a] = s_t - c_stay  # failed eat = stay
